const isHostile = function (e) {
  if (!e || e === bot.entity || e.type !== 'mob') return false;
  const hostileNames = ['zombie', 'skeleton', 'creeper', 'spider', 'enderman', 'witch', 'guardian', 'pillager', 'ravager', 'evoker', 'vindicator', 'husk', 'drowned', 'stray', 'phantom', 'blaze', 'ghast', 'magma_cube', 'slime', 'hoglin', 'piglin_brute', 'wither_skeleton'];
  return hostileNames.includes(e.name) || e.kind === 'Hostile' || e.kind === 'Monster';
};
const hostiles = Object.values(bot.entities).filter(isHostile);
if (hostiles.length === 0) {
  return "<SAFE>: No hostile mobs detected to retreat from.";
}
let retreatDir = new Vec3(0, 0, 0);
let count = 0;
hostiles.forEach(function (mob) {
  const dist = bot.entity.position.distanceTo(mob.position);
  if (dist < 32) {
    const diff = bot.entity.position.minus(mob.position).normalize();
    retreatDir = retreatDir.plus(diff);
    count++;
  }
});
if (count === 0) {
  const closest = hostiles.sort((a, b) => bot.entity.position.distanceTo(a.position) - bot.entity.position.distanceTo(b.position))[0];
  retreatDir = bot.entity.position.minus(closest.position).normalize();
} else {
  retreatDir = retreatDir.scaled(1 / count).normalize();
}
const targetPos = bot.entity.position.plus(retreatDir.scaled(args.distance));
startBackgroundSkill(bot, 'retreat_to_safety', async function (token) {
  const movements = new Movements(bot);
  bot.pathfinder.setMovements(movements);
  try {
    const goal = new goals.GoalNear(targetPos.x, targetPos.y, targetPos.z, 2);
    await bot.pathfinder.goto(goal);
    if (!token.cancelled) {
      console.log('Successfully retreated to safe distance.');
    }
  } catch (err) {
    if (!token.cancelled) {
      console.error('Retreat interrupted:', err);
    }
  }
});
return "<RETREATING>: Moving to " + Math.floor(targetPos.x) + ", " + Math.floor(targetPos.z) + " to avoid " + count + " hostile(s).";
